PRINT_AND_WAIT_CR:
        CALL PRINT_STRING                ; $02BD  CD 45 02
SUB_02BD_1:
        CALL CONIN_UPPER                 ; $02C0  CD C8 02   ; [AI] read a key
        CP $0D                           ; $02C3  FE 0D      ; [AI] RETURN?
        JR NZ,SUB_02BD_1                 ; $02C5  20 F9      ; [AI] ignore everything until RETURN
        RET                              ; $02C7  C9

; [AI] Read one console character with direct console I/O (BDOS fn 6), spin until a
; [AI] key is ready, abort to warm boot on ^C ($03), and uppercase the result.
CONIN_UPPER:
        LD E,$FF                         ; $02C8  1E FF      ; [AI] fn 6 input request
        LD C,$06                         ; $02CA  0E 06      ; [AI] BDOS fn 6 = direct console I/O
        CALL BDOS_VEC                    ; $02CC  CD 05 00
        OR A                             ; $02CF  B7         ; [AI] no key ready?
SUB_02C8_1:
        JR Z,CONIN_UPPER                 ; $02D0  28 F6      ; [AI] poll until a key arrives
        CP $03                           ; $02D2  FE 03      ; [AI] ^C abort?
        JP Z,WBOOT_VEC                   ; $02D4  CA 00 00   ; [AI] ^C -> warm boot
        CP $60                           ; $02D7  FE 60      ; [AI] lowercase letter?
        RET C                            ; $02D9  D8         ; [AI] no -> return as-is
        SUB $20                          ; $02DA  D6 20      ; [AI] fold to uppercase
        RET                              ; $02DC  C9

        DEFB    $23                                              ; $02DD ; [AI] padding / unused byte before vars
; [AI] ===== RAM variables (initialised data within the loaded image) =====
SRC_DST_DRIVES:
        DEFB    $00                                              ; $02DE ; [AI] source drive number (low byte of {dst,src})
DST_DRIVE:
        DEFB    $00                                              ; $02DF ; [AI] destination drive number (high byte)
TRACKS_TO_COPY:
        DEFB    $00                                              ; $02E0 ; [AI] tracks to copy per pass (TPA top - 7 pages)
SINGLE_DRIVE_FLAG:
        DEFB    $00                                              ; $02E1 ; [AI] 0 = read phase / multi-drive, 1 = write phase
RESUME_VECTOR:
        DEFS    30, $00    ; $02E2  fill                          ; [AI] word: copy-pass resume target ($0030 sentinel = single drive) + scratch
STACK_TOP:
; [AI] Stack grows down from $0300; the banner / message strings begin here and the
; [AI] SP is set to $0300 so the strings sit just below the runtime stack.
        DEFB    "      APPLE ][ CP/M"    ; $0300  string
        DEFB    $0D    ; $0313  terminator
        DEFB    $0A,$31,$36,$20,$53,$65,$63,$74,$6F,$72,$20,$44,$69,$73,$6B,$20 ; $0314 ; [AI] "16 Sector Disk "
        DEFB    "Copy Program"    ; $0324  string
        DEFB    $0D    ; $0330  terminator
        DEFB    $0A,$20,$20,$20,$20,$28,$43,$29,$20,$31,$39,$38,$30,$20,$4D,$69 ; $0331 ; [AI] "    (C) 1980 Mi"
        DEFB    "crosoft"    ; $0341  string
        DEFB    $0D    ; $0348  terminator
        DEFB    $0A,$0D,$0A,$24                                  ; $0349 ; [AI] CRLF CRLF '$'
