        DEFB    $52,$20,$64,$69,$73,$6B,$20,$61,$6E,$64,$20,$70,$72,$65,$73,$73 ; $046E ; [AI] "R disk and press"
        DEFB    $20,$52,$45,$54,$55,$52,$4E,$20,$24              ; $047E ; [AI] " RETURN $"
