        DEFB    $64,$69,$73,$6B,$20,$61,$6E,$64,$20,$70,$72,$65,$73,$73,$20,$52 ; $0497 ; [AI] "disk and press R"
; [AI] ===== Embedded 6502 program (Apple side) =====
; [AI] From here on the bytes are 6502 machine code (note $A2 LDX, $A9 LDA, $20 JSR,
; [AI] $4C JMP, $60 RTS, $D0/$10/$90 branches). This is the raw track read/write
; [AI] routine the SoftCard hands to the Apple's 6502 when the Z-80 pokes $F000. It
; [AI] consumes the $F3xx parameters set up above (track in DSK_TRACK/$F000, command in
; [AI] DSK_COMMAND, direction in DSK_DRIVE, unit in DSK_SLOT) and writes its result to DSK_STATUS.
; [AI] The two DEFW entries below are 6502 byte pairs the Z-80 disassembler happened
; [AI] to resolve as code addresses; they are preserved verbatim as data.
        DEFB    $45,$54,$55,$52,$4E,$20,$24,$A2,$15,$8E,$E9,$03,$20,$03,$0E,$AD ; $04A7 ; [AI] "ETURN $" then 6502 code begins
        DEFB    $EA,$03,$D0,$21,$AE,$E1,$03,$E8,$E0,$10,$90,$05,$A2,$00,$EE,$E0 ; $04B7 ; [AI] 6502 code
        DEFB    $03,$8E,$E1,$03,$AE,$E9,$03,$E8,$E0,$C0          ; $04C7 ; [AI] 6502 code
        DEFW    SUB_02C8_1               ; $04D1 ; [AI] 6502 bytes ($D0,$02) resolved as addr -- data, preserved
        DEFB    $A2,$D0,$8E,$E9,$03,$C6,$00,$D0,$D4,$60,$10,$49,$B0,$20,$ED,$FD ; $04D3 ; [AI] 6502 code
        DEFB    $C9,$B0,$66,$06,$88,$D0,$D6,$A9,$A0,$4C,$ED,$FD,$19,$4D ; $04E3 ; [AI] 6502 code
        DEFW    TPA_START_5              ; $04F1 ; [AI] 6502 bytes ($0F,$01) resolved as addr -- data, preserved
        DEFB    $8B,$20,$89,$F6,$25,$39,$2B,$31,$B0,$3B,$EB,$F1,$06 ; $04F3 ; [AI] tail of 6502 code / scratch

